head.script:
scwin.comboRtnFlag01;
scwin.comboRtnFlag02;
scwin.interval01;
scwin.systemPathVal;
scwin.tempArray;

scwin.PG_EVENT_FG;
scwin.SAVE_EVENT;

scwin.udc_objNm;

scwin.onpageload = async function() {
    //전역변수값 셋팅함수.
	scwin.initSetVal();

    const codeOptions01 = [
        { grpCd: "LO114", compID: "lc_vsslPurpsCd" },  //선박용도 콤보에 공통코드셋팅처리. 
        { grpCd: "LO122", compID: "lc_holdKndCd" },  //HOLD 종류 콤보에 공통코드셋팅처리.
        { grpCd: "LO123", compID: "lc_htccvrTypCd" },  //해치카바 TYPE 콤보에 공통코드셋팅처리.
    ];
    $c.data.setCommonCode(codeOptions01, scwin.commonCodeCallBack01);

    const codeOptions02 = [ 
        {
            method: "getLuxeComboData", 
            param1: "EquipmentEBC", 
            param2: "retrieveLogisticsEquipmentClss",
            param3: ["ZZ210","ZZ202","ZZ201","LH","Y"],
            compID: "gr_outEq:eqKndCd"
        }
    ];
    $c.data.setGauceUtil(codeOptions02, scwin.commonCodeCallBack02);

    scwin.interval01 = setInterval(async function() {
        if(scwin.comboRtnFlag01 == true && scwin.comboRtnFlag02 == true) {
            clearInterval(scwin.interval01);
            //초기화
  	        await scwin.f_OnLoad();
        }
    }, 300);
};

scwin.initSetVal = function() {
    scwin.comboRtnFlag01 = false;
    scwin.comboRtnFlag02 = false;

    scwin.systemPathVal = "/cm/bc/cstmrcardmgnt/cstmrcardmgnt/";

    scwin.PG_EVENT_FG = 0;
    scwin.SAVE_EVENT = 1;

    scwin.tempArray = [];

    scwin.udc_objNm = "";
};


scwin.commonCodeCallBack01 = function() {
    //초기화 처리.
    lc_vsslPurpsCd.setValue("");
    lc_holdKndCd.setValue("");
    lc_htccvrTypCd.setValue("");

    scwin.comboRtnFlag01 = true;
};

scwin.commonCodeCallBack02 = function() {
    scwin.comboRtnFlag02 = true;
};


scwin.f_OnLoad = async function() {

    //scwin.cfDisableKeyData();
    $c.gus.cfDisableKeyData();
    btn_AddRow.setDisabled(true);
    btn_DeleteRow.setDisabled(true);
    btn_UndoRow.setDisabled(true);

    btn_DeleteRow2.setDisabled(true);
    btn_UndoRow2.setDisabled(true);

    btn_upload.setDisabled(true);

    $c.gus.cfDisableBtn([btn_edit, btn_save, btn_delete]);

    //cfDisableObjects([img_clntPop, img_linePop, file_reg, file_del, file_reg2, file_del2, file_reg3, file_del3]);
    $c.gus.cfDisableObjects([btn_clntPop, btn_linePop, file_del, file_del2, file_del3]); 

    //to-do W-Gear 필요. 
    //cfSetIMEModeActiveObjects([txt_vsslNm]);

    /************************************************************
    * 장비규격명 lookup DataSet Setting 시작
    ************************************************************/
    dma_LkEqNrm.set("grpCd", "ZZ208");
    dma_LkEqNrm.set("cd", "");
    dma_LkEqNrm.set("cdNm", "");

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_LkEqNrm);
    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {  
        await scwin.sbm_LkEqNrm_submitdone();
    }
    /************************************************************
    * 장비규격명 lookup DataSet Setting 끝
    ************************************************************/
};

scwin.sbm_LkEqNrm_submitdone = async function (e) {
};


//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = async function () {
    //하기 로직은 신규버튼 클릭후 다시 신규버튼 시
    //as-is 경우 CanRowPosChange 이벤트에서 Validate 체크하지만
    //to-be 는 onbeforeRowChange 이벤트가 아닌 OnRowChange 이벤트를 태우므로
    //해당 로직 추가함.
    if(ds_out.getRowPosition() != undefined && ds_out.getRowPosition() != null) {
        var vsslCd = ds_out.getCellData(ds_out.getRowPosition(), "vsslCd");
        var vsslNm = ds_out.getCellData(ds_out.getRowPosition(), "vsslNm");
        if(ds_out.getRowStatus(ds_out.getRowPosition()) == "C") {
            if(vsslCd == "" || vsslNm == "" && scwin.PG_EVENT_FG != scwin.SAVE_EVENT) {
                let ret = await $c.gus.cfValidate([oRecevInfo]);

                if (!ret) {
                    //as-is 버그
                    //$c.gus.cfEnableKeyData();

                    btn_AddRow.setDisabled(true);
                    btn_DeleteRow.setDisabled(true);
                    btn_UndoRow.setDisabled(true);

                    btn_DeleteRow2.setDisabled(true);
                    btn_UndoRow2.setDisabled(true);

                    btn_upload.setDisabled(true);

                    $c.gus.cfDisableBtn([btn_save]);
                    $c.gus.cfDisableObjects([oRecevInfo, btn_clntPop, btn_linePop, file_del, file_del2, file_del3]);

                    ds_outEq.removeAll();
                    ds_outEqHold.removeAll();

                    gr_out.setFocusedCell(ds_out.getRowPosition(), 0);
                    return;
                }
            }
        }
    }

    var nRow = ds_out.getRowCount();
    ds_out.insertRow(nRow);
    //scwin.dma_out_row_SetData(nRow);
    gr_out.setFocusedCell(nRow, 0);

    ds_out.setCellData(nRow, "ocshipYn", 1.0);
    ds_out.setCellData(nRow, "useYn", 1.0);


    ds_out.setCellData(nRow, "len", 0);
    ds_out.setCellData(nRow, "draft", 0);
    ds_out.setCellData(nRow, "wid", 0);
    ds_out.setCellData(nRow, "totTonCnt", 0);
    ds_out.setCellData(nRow, "netTonCnt", 0);
    ds_out.setCellData(nRow, "shipwgtTonCnt", 0);
    ds_out.setCellData(nRow, "shipwgtTeuCnt", 0);
    ds_out.setCellData(nRow, "holdCnt", 0);



    //scwin.cfEnableKeyData();
    $c.gus.cfEnableKeyData();
    btn_AddRow.setDisabled(false);
    btn_DeleteRow.setDisabled(false);
    btn_UndoRow.setDisabled(false);

    btn_DeleteRow2.setDisabled(false);
    btn_UndoRow2.setDisabled(false);

    btn_upload.setDisabled(false);

    $c.gus.cfEnableObjects([btn_clntPop, btn_linePop, btn_edit, btn_save, btn_delete, file_del, file_del2, file_del3]); 

    ds_outEq.removeAll();
    ds_outEqHold.removeAll();
    ds_attach.removeAll();
    ds_attach2.removeAll();

    gr_outEq.setReadOnly("column","vsslEqNo",false);
    gr_outEq.setReadOnly("column","vsslEqNm",false);
    gr_outEq.setReadOnly("column","eqKndCd",false);
    gr_outEq.setReadOnly("column","eqNrmCd",false);

    //gr_outEq.setReadOnly("column","vsslEqCnt",false);
};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function() {
    if(ds_out.getModifiedIndex().length == 0 && 
       ds_outEq.getModifiedIndex().length + ds_outEq.getDeletedData().length == 0 && 
       ds_outEqHold.getModifiedIndex().length + ds_outEqHold.getDeletedData().length == 0 &&
       ds_attach.getModifiedIndex().length + ds_attach.getDeletedData().length == 0 &&
       ds_attach2.getModifiedIndex().length + ds_attach2.getDeletedData().length == 0) {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["선박정보"]);
        return;
    }

    //선박정보  필수 입력사항을 체크
    let ret = await $c.gus.cfValidate([oRecevInfo]);
    if (!ret) {
        return;
    }

    var strCallsignCd = ds_out.getCellData(ds_out.getRowPosition(), "callsignCd");


    for (var i=0; i<ds_out.getRowCount(); i++) {
        if (i != ds_out.getRowPosition() && strCallsignCd == ds_out.getCellData(i, "callsignCd")) {
            await $c.win.alert("선박호출번호가 중복되었습니다.");
            return;
        }
    }

    //장비별 HOLD 필수 입력사항을 체크
    for (var idx=0; idx<ds_outEqHold.getRowCount(); idx++) {
        if (ds_outEqHold.getCellData(idx, "holdNo") == "" ) {
            await $c.gus.cfAlertMsg(MSG_CM_ERR_002, ["HOLD번호"]);  //HOLD번호를  입력해 주십시요.
            return;
        }
    }
    scwin.PG_EVENT_FG = scwin.SAVE_EVENT;

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_save);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_save_submitdone();
    }

    gr_outEq.setReadOnly("column","vsslEqNo",true);
    gr_outEq.setReadOnly("column","vsslEqNm",true);
    gr_outEq.setReadOnly("column","eqKndCd",true);
    gr_outEq.setReadOnly("column","eqNrmCd",true);

    //gr_outEq.setReadOnly("column","vsslEqCnt",true);

    $c.gus.cfEnableKeyData();
    btn_AddRow.setDisabled(false);
    btn_DeleteRow.setDisabled(false);
    btn_UndoRow.setDisabled(false);

    btn_DeleteRow2.setDisabled(false);
    btn_UndoRow2.setDisabled(false);

    btn_upload.setDisabled(false);

    $c.gus.cfDisableBtn([btn_save]);   
    $c.gus.cfDisableObjects([oRecevInfo, btn_clntPop, btn_linePop, file_del, file_del2, file_del3]);
    $c.gus.cfTurnCreateFlag(false);
};



//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function() {
    $c.gus.cfDisableKey();

    $c.gus.cfDisableBtn([btn_create, btn_edit, btn_delete]);
    $c.gus.cfEnableObjects([btn_clntPop, btn_linePop, file_del, file_del2, file_del3]);

    gr_outEq.setReadOnly("column","vsslEqNo",false);
    gr_outEq.setReadOnly("column","vsslEqNm",false);
    gr_outEq.setReadOnly("column","eqKndCd",false);
    gr_outEq.setReadOnly("column","eqNrmCd",false);

    //gr_outEq.setReadOnly("column","vsslEqCnt",false);


    btn_AddRow.setDisabled(false);
    btn_DeleteRow.setDisabled(false);
    btn_UndoRow.setDisabled(false);

    btn_DeleteRow2.setDisabled(false);
    btn_UndoRow2.setDisabled(false);
    btn_upload.setDisabled(false);
};



//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function() {
    var v_status = ds_out.getRowStatus(ds_out.getRowPosition());

    if (ds_out.getRowCount()==0 || v_status=="C") {
        await $c.gus.cfAlertMsg(MSG_CM_ERR_003, ["삭제"]); 
        return;
    } else {
        let rtn = await $c.win.confirm(MSG_CM_CRM_004);

        if (rtn) {

            ds_out.removeRow(ds_out.getRowPosition());

            //submit 처리.
    		let objSubmit = await $c.sbm.execute(sbm_delete);

            if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
                await scwin.sbm_delete_submitdone();
            }

            $c.gus.cfTurnCreateFlag(false);	// Create 속성 초기화

            gr_outEq.setReadOnly("column","vsslEqNo",true);
            gr_outEq.setReadOnly("column","vsslEqNm",true);
            gr_outEq.setReadOnly("column","eqKndCd",true);
            gr_outEq.setReadOnly("column","eqNrmCd",true);

            //gr_outEq.setReadOnly("column","vsslEqCnt",true);

            $c.gus.cfTurnCreateFlag(false);
        }
    }
};

scwin.sbm_delete_submitdone = async function (e) {
    await $c.gus.cfAlertMsg(MSG_CM_INF_004, ["삭제결과"]);

	if ($c.gus.cfCheckCreateFlag() == true) {
      	 $c.gus.cfTurnCreateFlag(false);
    }
};


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    // 미사용여부 Check
    if (chk_cnd_useYn.getValue() == "0") {
        dma_condition.set("useYn", 1.0);
    } else {
        dma_condition.set("useYn", 0.0);
    }

    //submit 처리.
    let objSubmit = await $c.sbm.execute(sbm_retrieve);

    if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
        await scwin.sbm_retrieve_submitdone();
    }  
};

scwin.sbm_retrieve_submitdone = async function (e) {
    //scwin.cfEnableKeyData();
    $c.gus.cfEnableKeyData();
    btn_AddRow.setDisabled(false);
    btn_DeleteRow.setDisabled(false);
    btn_UndoRow.setDisabled(false);

    btn_DeleteRow2.setDisabled(false);
    btn_UndoRow2.setDisabled(false);

    btn_upload.setDisabled(false);

    $c.gus.cfDisableBtn([btn_save]);
    $c.gus.cfDisableObjects([oRecevInfo, btn_clntPop, btn_linePop, file_del, file_del2, file_del3]);

    gr_outEq.setReadOnly("column","vsslEqNo",true);
    gr_outEq.setReadOnly("column","vsslEqNm",true);
    gr_outEq.setReadOnly("column","eqKndCd",true);
    gr_outEq.setReadOnly("column","eqNrmCd",true);

    //gr_outEq.setReadOnly("column","vsslEqCnt",true);

    /**************************************************************************************
    * for=ds_out event=OnLoadCompleted 시작.
    **************************************************************************************/
    if ($c.gus.cfCheckCreateFlag() == true){ //신규 
        var nRow = ds_out.getRowCount();
        ds_out.insertRow(nRow);
        //scwin.dma_out_row_SetData(nRow);
        gr_out.setFocusedCell(nRow, 0);

	    ds_outEq.removeAll();
	    ds_outEqHold.removeAll();

	    //luxecombo 초기값 설정
        lc_vsslPurpsCd.setValue("");

	    // Radio 초기값 설정 
	    rd_ocShipYn.setValue("1");
	    rd_useYn.setValue("1");

	  	$c.gus.cfEnableObjects([oRecevInfo]);
	    $c.gus.cfDisableBtn([btn_create, btn_edit, btn_delete]);
	    ed_vsslCd.focus();
    } else { 
        totalRows1.setValue(ds_out.getRowCount());
		if( ds_out.getRowCount() == 0 ){
			await $c.gus.cfAlertMsg(MSG_CM_WRN_002, ["조회결과"]);  	

			//scwin.cfDisableKeyData();
            $c.gus.cfDisableKeyData();
            btn_AddRow.setDisabled(true);
            btn_DeleteRow.setDisabled(true);
            btn_UndoRow.setDisabled(true);

            btn_DeleteRow2.setDisabled(true);
            btn_UndoRow2.setDisabled(true);

            btn_upload.setDisabled(true);

			$c.gus.cfDisableBtn([btn_edit, btn_save, btn_delete]);

		}else{
            gr_out.setFocusedCell(0, 0);

			// 조회조건
		    dma_conditionDetail.set("vsslCd", ds_out.getCellData(0,"vsslCd"));
		    dma_conditionDetail.set("shpCoClntNo", ds_out.getCellData(0,"shpCoClntNo"));

            let objSubmit;

            //submit 처리.
            objSubmit = await $c.sbm.execute(sbm_retrieveFile);

            if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
                await scwin.sbm_retrieveFile_submitdone();
            }

            //submit 처리.
            objSubmit = await $c.sbm.execute(sbm_retrieveFile2);

            if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
                await scwin.sbm_retrieveFile2_submitdone();
            }

            //submit 처리.
            objSubmit = await $c.sbm.execute(sbm_retrieveEq);

            if(objSubmit.responseJSON.resultDataSet[0].Msg == "SUCC") {   
                await scwin.sbm_retrieveEq_submitdone();
            }

			$c.gus.cfDisableKey();
			$c.gus.cfDisableObjects([oRecevInfo]);
	      	$c.gus.cfEnableAllBtn();
	      	$c.gus.cfDisableBtn([btn_save]);
	  	}
	}
    /**************************************************************************************
    * for=ds_out event=OnLoadCompleted 끝.
    **************************************************************************************/
};

scwin.sbm_retrieveFile_submitdone = async function (e) {
    totalRows4.setValue(ds_attach.getRowCount());
};

scwin.sbm_retrieveFile2_submitdone = async function (e) {
    if( ds_attach2.getRowCount() != 0 ){
	    for(var i = 0; i < ds_attach2.getRowCount(); i++) {
  			scwin.f_previewImg(i);
  		}
	}else{
        preView.setSrc("");
        preView.setStyle("width", "0px");
        preView.setStyle("height", "0px");
		preView2.setSrc("");
        preView2.setStyle("width", "0px");
        preView2.setStyle("height", "0px");
		preView3.setSrc("");
        preView3.setStyle("width", "0px");
        preView3.setStyle("height", "0px");
	}
};

scwin.sbm_retrieveEq_submitdone = async function (e) {
    totalRows2.setValue(ds_outEq.getRowCount());
};

//-------------------------------------------------------------------------
// 파일을 업로드한다.
//-------------------------------------------------------------------------
scwin.f_Submit = function () {
    udc_fielUpload.setSubDir(scwin.systemPathVal);
    udc_fielUpload.startFileUpload();
};



//-------------------------------------------------------------------------
// function name : uploadComplete
// function desc : Upload File complete 
//-------------------------------------------------------------------------
scwin.uploadComplete = function (isSuccess) {
    if(!isSuccess) {
        return;
    }

    let data = udc_fielUpload.getData();

    for ( i = 0; i < data.length; i++) {
        var nRow = ds_attach.getRowCount();
        ds_attach.insertRow(nRow);

        if ( ds_attach.getRowCount() != 1 ) {
            var fltNxtSeq = parseFloat(ds_attach.getCellData(nRow - 1,"attachFileId")) + 1;
            var strNxtSeq = "000" + fltNxtSeq;

            strNxtSeq = strNxtSeq.substr(strNxtSeq.length - 4, strNxtSeq.length);			
            ds_attach.setCellData(nRow,"attachFileId", strNxtSeq);
        } else {
            ds_attach.setCellData(nRow,"attachFileId", "0001");
        }

        ds_attach.setCellData(nRow, "vsslCd", ed_vsslCd.getValue());  // 선박코드
        ds_attach.setCellData(nRow, "attachFileNm", data[i].ORIGIN_FILE_NM); // 파일명
        ds_attach.setCellData(nRow, "attachFileDesc", data[i].ORIGIN_FILE_NM); // 파일설명
        ds_attach.setCellData(nRow, "attachFileSiz", data[i].FILE_SIZE); // 파일SIZE
        ds_attach.setCellData(nRow, "salesActivId", ed_vsslCd.getValue());	// 파일ID
        ds_attach.setCellData(nRow, "attachFilePath", data[i].FILE_STORED_PATH + data[i].STORED_FILE_NM);	// 파일경로

        gr_attachFile.setFocusedCell(nRow, "attachFileId");
    }

    udc_fielUpload.setGridClear();
};


//-------------------------------------------------------------------------
// 행 추가 - 선박별 장비
//-------------------------------------------------------------------------
scwin.f_AddRowEquipment = async function () {
    let ret = await $c.gus.cfValidate([oRecevInfo]);
    if (!ret) {
        return;
    }

    var nRow = ds_outEq.getRowCount();

    ds_outEq.insertRow(nRow);
    ds_outEq.setCellData(nRow, "vsslCd", ds_out.getCellData(ds_out.getRowPosition(),"vsslCd"));

    //default 값으로 0 셋팅되므로 하기로직 추가.
    ds_outEq.setCellData(nRow, "vsslEqCnt", 0);

    gr_outEq.setReadOnly("column","vsslEqNo",false);
    gr_outEq.setReadOnly("column","vsslEqNm",false);
    gr_outEq.setReadOnly("column","eqKndCd",false);
    gr_outEq.setReadOnly("column","eqNrmCd",false);

    //행추가시 수정되어야 하므로 하기로직 추가.
    //gr_outEq.setReadOnly("column","vsslEqCnt",false);

    gr_outEq.setFocusedCell(nRow, "vsslEqCnt");
};



//-------------------------------------------------------------------------
// 행 삭제 - 선박별 장비
//-------------------------------------------------------------------------
scwin.f_DeleteRowEquipment = function () {
    var v_vsslCd = ds_outEq.getCellData(ds_outEq.getRowPosition(), "vsslCd");

    // 장비별 HOLD 항목 삭제 
    for (i=0; i<ds_outEqHold.getRowCount(); i++) {
        if (v_vsslCd == ds_outEqHold.getCellData(i, "vsslCd")) {
            ds_outEqHold.removeRow(i);
        }
    }

    ds_outEq.removeRow(ds_outEq.getRowPosition());

    gr_outEq.setFocusedCell(0, "vsslEqCnt");
};


//-------------------------------------------------------------------------
// 행 취소 (Undo) - 선박별 장비
//-------------------------------------------------------------------------
scwin.f_UndoRowEquipment = function () {
    var v_vsslCd = ds_outEq.getCellData(ds_outEq.getRowPosition(), "vsslCd");

    // 장비별 HOLD 항목 취소 (Undo)
    for (i=0; i<ds_outEqHold.getRowCount(); i++) {
        if (v_vsslCd == ds_outEqHold.getCellData(i, "vsslCd")) {
            //ds_outEqHold.Undo(i);
            $c.data.undoRow(ds_outEqHold, "Y");
        }
    }

    //ds_outEq.Undo(ds_outEq.getRowPosition());
    $c.data.undoRow(ds_outEq, "Y");
};


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (callObj, disGubun, pCode, pName, pClose, pAllSearch, row) {
    scwin.udc_objNm = callObj.org_id;

    if(row == null) {
        row = 0;
    }

    // 선언부
    var rtnList = new Array();  // 공통POP-UP -> 요청화면 

    switch (disGubun) { 

        case 1:
            //초기화 처리.
            ed_cnd_shpCoClntNo.setValue("");
            ed_cnd_shpCoClntNm.setValue("");

            callObj.setSelectId("retrieveClntInfo");

            //선사코드 팝업			
            await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc	// XML상의 SELECT ID	
                                ,pCode				// 화면에서의 ??? Code Element의	Value
                                ,pName				// 화면에서의 ??? Name Element의	Value
                                ,pClose				// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                ,null				// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null				// Title순서	
                                ,null				// 보여주는 각 컬럼들의 폭	
                                ,null				// 컬럼중에서 숨기는	컬럼 지정	
                                ,'SHP'				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                ,null				// POP-UP뛰을때 원도우의	사용자 정의	폭
                                ,null				// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                ,null				// 윈도우 위치 Y좌표	
                                ,null				// 윈도우 위치 X좌표
                                ,null
                                ,'F'
                                ,null
                                ); 
            break;

        case 2:
            //초기화 처리.
            ed_shpCoClntNm.setValue("");

            callObj.setSelectId("retrieveClntInfo");

            //선사팝업
            await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc	// XML상의 SELECT ID	
                                ,pCode				// 화면에서의 ??? Code Element의	Value
                                ,pName				// 화면에서의 ??? Name Element의	Value
                                ,pClose				// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                ,null				// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null				// Title순서	
                                ,null				// 보여주는 각 컬럼들의 폭	
                                ,null				// 컬럼중에서 숨기는	컬럼 지정	
                                ,'SHP'				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                ,null				// POP-UP뛰을때 원도우의	사용자 정의	폭
                                ,null				// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                ,null				// 윈도우 위치 Y좌표	
                                ,null				// 윈도우 위치 X좌표
                                ,null
                                ,'F'
                                ,null
                                );
            break;

        case 3:
            //초기화 처리.
            ed_lineNm.setValue("");

            callObj.setSelectId("retrieveLineInfo");

            // LINE팝업
            await callObj.cfCommonPopUp(scwin.udc_AllInOne_callBackFunc	// XML상의 SELECT ID	
                                ,pCode				// 화면에서의 ??? Code Element의	Value
                                ,pName				// 화면에서의 ??? Name Element의	Value
                                ,pClose				// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                ,null				// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null				// Title순서	
                                ,null				// 보여주는 각 컬럼들의 폭	
                                ,null				// 컬럼중에서 숨기는	컬럼 지정	
                                ,null				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                ,null				// POP-UP뛰을때 원도우의	사용자 정의	폭
                                ,null				// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                ,null				// 윈도우 위치 Y좌표	
                                ,null				// 윈도우 위치 X좌표
                                ,null
                                ,'F'
                                ,null
                                ); 
            break;

    default:
        break;
    }
};

scwin.udc_AllInOne_callBackFunc = function (rtnList) {
    let codeObj;
    let nameObj;

    if(scwin.udc_objNm == "udc_ed_cnd_shpCoClnt") {
        codeObj = ed_cnd_shpCoClntNo;
        nameObj = ed_cnd_shpCoClntNm;
    } else if(scwin.udc_objNm == "udc_ed_shpCoClnt") {
        codeObj = hid_shpCoClntNo;
        nameObj = ed_shpCoClntNm;
    } else if(scwin.udc_objNm == "udc_ed_line") {
        codeObj = hid_lineCd;
        nameObj = ed_lineNm;     
    }

    $c.gus.cfSetReturnValue(rtnList, codeObj, nameObj);
};


//-------------------------------------------------------------------------
// POP-UP Call전 Checking
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function (callObj, inObj, pairObj, disGubun, isCode) {
    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }
    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        await scwin.f_openCommonPopUp(callObj, disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    } else {
        await scwin.f_openCommonPopUp(callObj, disGubun, '', pVal, 'T', 'T');
    }
};


