scwin.f_ZoomIn = async function (row) {
    if(ds_attach2.getRowCount() != 0 && row < ds_attach2.getRowCount()){
    	/*
        var style = "center:yes; dialogwidth:840px; dialogheight:660px; dialogleft:100px; dialogtop:50px; scroll:Yes; resizable:Yes; status:no;";
        var strUrl = "./zoom.html";
        var strParam = $c.gus.cfGetFileURL("",ds_attach2.getCellData(row ,"attachFilePath"));
        window.showModalDialog(strUrl,strParam, style );
        */

        //to-do 업무공통에서 봐줘야함.
        //현재 to-be는 s서버(클라우드서버)에 파일업로드 처리하므로
        //zoom.xml 파일내 로직을 변경처리(업무공통) 해야함.
        let strUrl = "/cm/xml/zoom.xml";
        let filePath = ds_attach2.getCellData(row ,"attachFilePath");
        let previewUrl = $c.gus.cfGetFileURL("", filePath);
        await $c.win.openPopup(strUrl, {
            width: 840,
            height: 660,
            modal: true
        }, {
            fileName: ds_attach2.getCellData(row, "attachFileNm"),
            filePath: filePath,
            previewUrl: previewUrl
        });
    }
};


