scwin.gr_outEq_onbeforeedit = function (rowIndex, columnIndex, value) {
    //장비규격명 item 필터링 처리.
    if(columnIndex == 4) {
        if(ds_outEq.getCellData(rowIndex, "eqKndCd") != "") {
            scwin.gr_outEq_eqNrmCd_setFilter(rowIndex);
