//for=gr_outEq event=OnCloseUp
//Grid Column의 EditStyle이 Combo 또는 Lookup일 경우 Combo가 닫힐 때 발생한다.
//Grid에서 Combo를 사용해 Data를 선택시 OnCloseUp 이벤트를 사용해 다른 작업을 수행할수 있도록 한다.
//=> onafteredit 함수내에서 셋팅처리.(사유: onafteredit 함수내에서 필터 초기화처리 로직 존재.)
scwin.gr_outEq_oneditend = function (rowIndex, columnIndex, value) {
    if(columnIndex == 3) {
        //empty 값 셋팅위한 최상위 row 추가. 
        if(ds_LkEqNrm.getCellData(0, "initYN") == "") {
            ds_LkEqNrm.insertRow(0);
            ds_LkEqNrm.setCellData(0, "initYN", "Y");
            ds_LkEqNrm.reform();
        }
    } else if(columnIndex == 4) {
        //empty 값 셋팅위한 최상위 row 추가. 
        if(value == "" && ds_LkEqNrm.getCellData(0, "initYN") == "") {
            ds_LkEqNrm.insertRow(0);
            ds_LkEqNrm.setCellData(0, "initYN", "Y");
            ds_LkEqNrm.reform();
        }
    }
};

//event=OnExit 처리위한 로직1.(변경되기전 정보 가져오기)
scwin.ds_outEq_onbeforecelldatachange = function (info) {

};

//event=OnExit 처리위한 로직2.(별도 함수 호출위한 로직)
//그리드 cell focus out 처리(상기 로직1의 변경되기전 정보가 없는 경우도 호출함.)
scwin.gr_outEq_onafteredit = function (rowIndex, columnIndex, value) {
    /************************************************************************
    * for=gr_outEq event=OnCloseUp 이벤트 시작.
    ************************************************************************/
    // 장비종류명 또는 장비규격명 수정(focus out) 시
    if(columnIndex == 3 || columnIndex == 4) {
        //장비규격명 item 필터링 해제 및 empty 값 셋팅된 row 삭제 처리.
        if(ds_LkEqNrm.getRowCount() < ds_LkEqNrm.getAllJSON().length) {
            ds_LkEqNrm.clearFilter();

            //장비규격명 item 보여주기전 empty 값 셋팅된 row 삭제처리.
            for(var i=0;i<ds_LkEqNrm.getRowCount();i++) {
                if(ds_LkEqNrm.getCellData(i, "initYN") == "Y") {
                    ds_LkEqNrm.removeRow(i);
                }
            }

            ds_LkEqNrm.reform();
        }
    }
    /************************************************************************
    * for=gr_outEq event=OnCloseUp 이벤트 끝.
    ************************************************************************/

};

